	(1,'about','main_content','html','\n            <div data-cms-editable=\"main_content\" data-cms-page=\"about\" data-cms-type=\"html\" class=\"cms-editable cms-editing cms-saved\" contenteditable=\"true\"><p>Click here to add your content...</p></div>        ',NULL,2,'2026-03-05 10:32:45',1),
	(2,'home','hero_tagline','text','YOU BELONG HERE',NULL,11,'2026-03-11 16:01:03',1),
	(3,'home','hero_headline','text','Church for everyone, including you.',NULL,5,'2026-03-11 15:55:34',1),
	(4,'home','newhere_text','html','<p>Let us know you are visiting and we will save you a seat and make sure you are welcome. Alive Church is for everyone, and we want to make you feel welcome, no matter what you believe or where you are on your journey.<br><strong>We are so excited to meet you!</strong></p>',NULL,5,'2026-03-10 12:22:32',1),
	(5,'home','newhere_eyebrow','text','First Time?',NULL,1,'2026-03-05 10:33:00',1),
	(6,'home','weekend_headline','text','Happening at Alive',NULL,1,'2026-03-05 10:33:12',1),
	(7,'home','about_headline','text','Live fully alive in Jesus.',NULL,1,'2026-03-05 10:33:18',1),
	(8,'home','about_text','html','<p>We exist to help every person know God, find family, discover purpose, and make a difference. Whether you grew up in church or you\'re just exploring faith, you can belong here in our family.</p>',NULL,3,'2026-03-10 12:23:51',1),
	(9,'home','sidebar_headline','text','We saved you a seat.',NULL,1,'2026-03-05 10:33:20',1),
	(10,'home','hero_subtext','text','Life-giving worship, practical teaching, and real community in Norwich and online.',NULL,21,'2026-03-11 16:03:15',1),
	(11,'home','newhere_headline','text','We saved you a seat.',NULL,2,'2026-03-10 12:22:25',1),
	(12,'home','sermon_headline','text','Watch this week\'s teaching.',NULL,2,'2026-03-11 16:13:31',1),
	(13,'home','ministries_eyebrow','text','Ministries & Projects',NULL,1,'2026-03-05 10:46:14',1),
	(14,'home','watch_headline','text','Catch up on the latest series.',NULL,1,'2026-03-05 10:46:18',1),
	(15,'home','events_eyebrow','text','Don\'t miss out',NULL,1,'2026-03-05 10:46:23',1),
	(16,'visit','expect_content','html','<ul class=\"info-list\">\n                <li><strong>Services:</strong> Sundays • 11:00AM with live worship &amp; teaching.</li>\n                <li><strong>Kids:</strong> Kids go out to their own dedicated teaching programme after the worship. They\'re sure to have fun.</li>\n                <li><strong>Parking:</strong> Parking is available on Arms Street at the Nelson First School Car Park. Look for the Alive Church Parking sign.</li>\n                <li><strong>Dress:</strong> Trainers or ties, come as you are.</li>\n            </ul>\n            <p>Need extra assistance? Let us know in the form, and we will make accommodations.&nbsp;</p>',NULL,6,'2026-03-10 12:06:11',1),
	(17,'visit','expect_headline','text','What to expect',NULL,1,'2026-03-05 10:46:50',1),
	(18,'visit','location_headline','text','We\'re easy to find.',NULL,1,'2026-03-05 10:46:55',1),
