	(28,'connect','groups_headline','text','Join a Group',NULL,2,'2026-03-05 20:25:31',1),
	(29,'connect','groups_subtext','text','Life change happens in circles, not rows. Find a group that fits your season, interests, and schedule.',NULL,1,'2026-03-05 20:12:35',1),
	(30,'connect','hero_subtext','text','From groups to serve teams, there\'s a place for everyone to belong, grow, and make a difference.',NULL,1,'2026-03-05 20:12:36',1),
	(31,'connect','hero_headline','text','Find your people. Use your gifts.',NULL,2,'2026-03-05 20:12:37',1),
	(32,'connect','hero_eyebrow','text','Connect',NULL,1,'2026-03-05 20:12:38',1),
	(33,'about','hero_eyebrow','text','About Alive',NULL,1,'2026-03-05 20:15:40',1),
	(34,'about','hero_headline','text','Our story & values.',NULL,3,'2026-03-07 16:50:13',1),
	(35,'about','whoweare_content','html','<p class=\"intro-text\">Alive Church was started over 40 years ago as a small group of charismatic Christians in a living room, in a city without a charismatic church. Today, Alive Church is thriving Pentecostal church, a family of all kinds of people doing life together.</p><p>testtestetssssss</p>',NULL,16,'2026-03-10 12:10:23',1),
	(36,'about','leader2_name','text','Pastor Jono Thorne',NULL,2,'2026-03-05 20:18:43',1),
	(37,'about','leader2_bio','text','Jono oversees many aspects of church life. He is always doing something new and is responsible for Worship, Creative, Youth, Facilities management and Operations in the church.',NULL,3,'2026-03-05 20:19:12',1),
	(39,'about','leader3_bio','text','Sara grew up in the church, and with her husband Jon, lead many aspects of church life. Sara can often be found preaching, whilst Jon plays drums. Together they lead Kids Church and Jon is trustee of Alive UK.',NULL,1,'2026-03-05 20:16:10',1),
	(41,'about','leader2_image','image','http://localhost:8999/storage/uploads/2026/03/356827709_696792935611765_8535916563847191511_n-919694a6.jpg',NULL,2,'2026-03-05 20:21:43',1),
	(42,'visit','hero_headline','text','Come hang with us this weekend!',NULL,3,'2026-03-05 21:28:34',1),
	(43,'visit','hero_subtext','text','Tell us you are coming, we\'d love to welcome you and save you a seat. There\'s a coffee with your name on it too.',NULL,9,'2026-03-05 21:49:39',1),
	(44,'events','hero_eyebrow','text','Events & Gatherings',NULL,2,'2026-03-05 20:48:50',1),
