	(47,'echo','page_content','html','\n    <section class=\"page-content\"><div class=\"container\"><p>Click here to start building your padge...</p></div></section>',NULL,1,'2026-03-05 20:58:39',1),
	(48,'echo','hero_heading','text','\n            ECHO        ',NULL,7,'2026-03-05 21:00:10',1),
	(49,'home','sermon_eyebrow','text','Latest Message',NULL,5,'2026-03-11 16:13:31',1),
	(50,'visit','hero_eyebrow','text','Plan a Visit',NULL,1,'2026-03-05 21:28:05',1),
	(51,'visit','timeline3_text','text','Kids join us for worship and then go out to their special kids programme just after worship. No need to register. Please take your child home with you, though.',NULL,2,'2026-03-05 21:32:55',1),
	(52,'visit','timeline4_text','text','60-75 minutes of worship, teaching, and prayer. Lyrics on screens. Seats, sofas and tables in back if you prefer. No pressure to participate.',NULL,3,'2026-03-05 21:33:26',1),
	(53,'visit','timeline5_title','text','Connect After',NULL,1,'2026-03-05 21:33:11',1),
	(54,'visit','timeline5_text','text','Stick around for more coffee and conversation in our Revive cafe. Our team can help you find groups, serve opportunities, or next steps.',NULL,2,'2026-03-05 21:33:43',1),
	(55,'visit','faq_content','html','\n            \n            <details class=\"faq-item\">\n                <summary>What should I wear?</summary>\n                <p>Come as you are! You\'ll see everything from jeans and trainers to dresses and suits. We care more about you than your outfit.</p>\n            </details>\n\n            <details class=\"faq-item\">\n                <summary>Is there parking?</summary>\n                <p>Yes! There is limited parking directly outside the church, and a large free carpark further down Arms Street with plenty of space available. Look for the \"Alive Church Parking\" sign.</p>\n            </details>\n\n            <details class=\"faq-item\">\n                <summary>What about my kids?</summary>\n                <p>They can join you, or head up to kids church - either is fine with us!</p>\n            </details>\n\n            <details class=\"faq-item\">\n                <summary>How long is the service?</summary>\n                <p>Plan for 60-75 minutes including worship, teaching, and prayer. You\'re welcome to arrive a few minutes late or leave early if needed. We won\'t condemn you from the stage.</p>\n            </details>\n\n            <details class=\"faq-item\">\n                <summary>Will I be asked to give money?</summary>\n                <p>We take up an offering for our church family, this is optional for everyone and first time visitors are not under any pressure to give. If you do however want to give towards our ministry, there are many easy and accessible ways to do so.</p>\n            </details>\n\n            <details class=\"faq-item\">\n                <summary>Can I bring my service dog?</summary>\n                <p>Absolutely! Service animals are always welcome. Please let us know when you register so we can prepare and assist as needed.</p>\n            </details>                ',NULL,3,'2026-03-05 21:36:48',1),
	(56,'bible-study','about_content','html','<h2>About These Studies</h2>\n<p>This tool was created to give us and you an easy way to look through the bible in context, study and understand the important verses that guide our faith. These in-depth Bible studies have been written to help you understand Scripture more deeply. Each study examines the text verse-by-verse, exploring the historical context, original language, and practical application for today.&nbsp;</p><p><b>Use this tool in conjunction with a bible.</b> We recommend <a href=\"https://www.waterstones.com/book/niv-holy-bible-hodder-classics/new-international-version/9781473697102\">the NIV translation </a>for their ease of reading and good accuracy, but there are many other great options!</p>\n<p><b>Whether you\'re new to Bible study or have been reading Scripture for years, we pray these resources will enrich your understanding and deepen your faith.</b></p><p>Writing a bible study for every chapter of the bible, all 1,189 of them is a lot of work. If you\'d like to get involved and become an author, please <a href=\"/contact-us\">contact us</a> to volunteer.</p>                                        ',NULL,6,'2026-03-07 08:03:56',NULL),
	(57,'bible-study','hero_eyebrow','text','Bible Study Library',NULL,4,'2026-03-07 17:52:33',1),
	(58,'watch','hero_subtext','text','Stream this week\'s message, browse past series, or listen on your favorite podcast platform.',NULL,1,'2026-03-07 15:38:10',NULL),
	(59,'watch','hero_headline','text','Church wherever you are.',NULL,1,'2026-03-07 15:38:11',NULL),
	(60,'watch','next_live_title','text','Next Live Stream',NULL,3,'2026-03-07 15:40:34',NULL),
