INSERT INTO `event_details` (`id`, `slug`, `title`, `subtitle`, `description`, `full_description`, `image`, `gallery`, `who_is_it_for`, `what_to_expect`, `what_to_bring`, `cost`, `registration_url`, `contact_email`, `contact_phone`, `custom_location`, `is_featured`, `meta_title`, `meta_description`, `created_at`, `updated_at`, `updated_by`)
VALUES
	(1,'sunday-service','Sunday Service','Join us for worship every Sunday','Our main weekly gathering with worship, teaching, and community.','<p>Sunday Service is the heartbeat of Alive Church. We gather together to worship God, hear from His Word, and connect with one another.</p><p>Whether you\'ve been following Jesus for years or you\'re just exploring faith, you\'re welcome here. Come as you are - no dress code, no judgement, just Jesus.</p>','/assets/imgs/gallery/alive-church-worship-congregation.jpg',NULL,'<ul><li>Everyone is welcome!</li><li>Families with children (we have kids programs)</li><li>Those exploring faith</li><li>Anyone looking for community</li></ul>','<ul><li>Contemporary worship music</li><li>Practical Bible teaching (30-40 mins)</li><li>Prayer and ministry time</li><li>Tea & coffee afterwards</li><li>Kids Church for ages 0-11</li></ul>',NULL,'Free',NULL,NULL,NULL,NULL,0,NULL,NULL,'2026-03-05 20:28:10','2026-03-05 20:28:10',NULL),
	(2,'alive-youth','Alive Youth','For ages 11-18','Games, worship, teaching, and community for young people.','<p>Alive Youth is a place where teenagers can belong, have fun, and grow in their faith. We believe the teenage years are some of the most formative, and we want to help young people navigate them with Jesus at the centre.</p><p>Each week we have games, worship, teaching from the Bible, and time to hang out and build friendships.</p>','/assets/imgs/gallery/alive-church-drummer-worship-team.jpg',NULL,'<ul><li>Ages 11-18</li><li>Both church kids and friends welcome</li><li>No church background needed</li></ul>','<ul><li>High-energy games and activities</li><li>Live worship</li><li>Relevant teaching</li><li>Small group discussions</li><li>Snacks and hangout time</li></ul>',NULL,'Free',NULL,NULL,NULL,NULL,0,NULL,NULL,'2026-03-05 20:28:10','2026-03-05 20:28:10',NULL),
	(3,'foodbank-and-community-cafe','Foodbank & Community Cafe','Serving our community','Free food, hot drinks, and a warm welcome for anyone in need.','<p>Our Foodbank and Community Cafe is open every Friday to serve our local community. Whether you need food support, a hot drink, or just someone to talk to, you\'re welcome here.</p><p>We partner with local food banks and supermarkets to provide groceries, and our volunteers serve hot drinks and snacks in a welcoming cafe environment.</p>','/assets/imgs/gallery/alive-church-community-cafe-outdoor.jpg',NULL,'<ul><li>Anyone in need of food support</li><li>Those experiencing hardship</li><li>Anyone wanting community connection</li><li>Volunteers welcome too!</li></ul>','<ul><li>Free grocery bags available</li><li>Hot drinks and snacks</li><li>Friendly conversation</li><li>Signposting to other services</li><li>Prayer available if wanted</li></ul>',NULL,'Free',NULL,NULL,NULL,NULL,0,NULL,NULL,'2026-03-05 20:28:10','2026-03-05 20:28:10',NULL),
	(4,'revive-cafe','Revive Cafe','Coffee, cake & community','A welcoming cafe space open to everyone in the community.','<p>Revive Cafe is our community coffee shop, open to everyone. Pop in for a coffee, grab some homemade cake, and enjoy the friendly atmosphere.</p><p>It\'s a great place to meet friends, work remotely, or just take a break from your day.</p>','/assets/imgs/gallery/alive-church-community-cafe-outdoor.jpg',NULL,'<ul><li>Everyone welcome</li><li>Parents with young children</li><li>Remote workers</li><li>Those wanting community</li></ul>','<ul><li>Quality coffee and tea</li><li>Homemade cakes and snacks</li><li>Free WiFi</li><li>Comfortable seating</li><li>Friendly volunteers</li></ul>','','Prices range, but we try and keep it as cheap as possible.','https://revive-cafe.co.uk','office@alive.me.uk','','',0,NULL,NULL,'2026-03-05 20:28:10','2026-03-11 14:03:56',NULL),
	(5,'crochet-and-knitting-group-crochet-and-knitting','Crochet & Knitting Group','Create together','A friendly group for crafters of all abilities.','<p>Join our friendly crochet and knitting group! Whether you\'re an experienced crafter or complete beginner, you\'re welcome to come along.</p><p>We share patterns, help each other with tricky stitches, and enjoy good company while we create.</p>','/assets/imgs/gallery/alive-church-worship-congregation.jpg',NULL,'<ul><li>All skill levels welcome</li><li>Beginners especially welcome</li><li>Anyone who enjoys crafts</li><li>Those looking for community</li></ul>','<ul><li>Bring your own project or start something new</li><li>Help available for beginners</li><li>Pattern sharing</li><li>Tea, coffee and chat</li></ul>',NULL,'Free',NULL,NULL,NULL,NULL,0,NULL,NULL,'2026-03-05 20:28:10','2026-03-05 20:28:10',NULL),
	(6,'alive-church-camping','ECHO2026','An invitation extended across centuries—a call demanding response','ECHO2026 is our annual church camp - a three-day weekend retreat at Sizewell Hall. This is no ordinary retreat; it\'s a Spirit-filled gathering for worship, community, and responding to God\'s call.','<p>ECHO2026 is our annual church camp weekend, taking place at the beautiful Sizewell Hall in Suffolk. This three-day retreat is an invitation extended across centuries—a call demanding response.</p>\r\n<p>Drawing from Revelation 22:17, this weekend is about responding to God\'s call together as a church family. Whether you\'re joining us for worship around the campfire, enjoying family-friendly activities, or simply resting in community, ECHO2026 is a weekend you won\'t want to miss.</p>\r\n<p>Accommodation options include bringing your own tent, caravan or campervan, or we can provide a tent for you.</p>','/assets/imgs/gallery/alive-church-worship-congregation.jpg',NULL,'<ul>\r\n<li>Adults and children of all ages</li>\r\n<li>Families looking for a faith-filled weekend away</li>\r\n<li>Anyone wanting to deepen their connection with the church community</li>\r\n<li>Infants aged 0-4 attend free</li>\r\n</ul>','<ul>\r\n<li>Spirit-led worship sessions</li>\r\n<li>Campfire worship under the stars</li>\r\n<li>Family-friendly activities and gatherings</li>\r\n<li>Communal meals together</li>\r\n<li>Time for rest and community connection</li>\r\n<li>Beautiful Suffolk countryside setting</li>\r\n</ul>','<ul>\r\n<li>Tent, caravan or campervan (or request one to be provided)</li>\r\n<li>Sleeping bag and camping essentials</li>\r\n<li>Warm layers for evening campfire worship</li>\r\n<li>Bible and notebook</li>\r\n<li>An open heart ready to encounter God</li>\r\n</ul>','Adult: £85 / Child: £55 / Day tickets available','https://echo.alivechur.ch','office@alive.me.uk','','Sizewell Hall, Sizewell, Leiston, Suffolk, IP16 4TX',0,NULL,NULL,'2026-03-05 20:28:10','2026-03-11 13:55:27',NULL),
	(7,'bible-study-connect-group','Bible Study Connect','An in-depth look at the Bible','Join us for an in-depth look at the bible for those wanting to go deeper. Bible Study Connect is perfect for new Christians and long-time experiences Christians alike.','Join us for an in-depth look at the bible for those wanting to go deeper. Bible Study Connect is perfect for new Christians and long-time experiences Christians alike. Join us for a night of study, food and friendship. Wether you are part of the furniture, or you are new and looking to connect, you are welcome.','',NULL,'<ul>\r\n<li>Anyone new to the bible</li>\r\n<li>Experienced Christians who can offer deeper insights</li>\r\n<li>Those looking to grow in their faith</li>\r\n</ul>','</ul>\r\n<li>Start with food, drink and chat</li>\r\n<li>We\'ll watch a video from The Bible Society course</li>\r\n<li>We\'ll discuss this video and break it down, asking questions and exploring together</li>\r\n</ul>','<ul>\r\n<li>Your bible, if you have one. If you don\'t, we\'ll give you one</li>\r\n<li>You are welcome to bring drinks or snacks to share, but this is not required and you can still partake in what others bring</li>\r\n</ul>','Free','','phil@alive.me.uk','07876770235','',0,NULL,NULL,'2026-03-11 14:01:45','2026-03-11 14:02:45',NULL);
