INSERT INTO `pages` (`id`, `slug`, `title`, `meta_description`, `content`, `template`, `layout`, `hero_style`, `builder_mode`, `grapes_html`, `grapes_css`, `grapes_components`, `grapes_styles`, `published`, `show_in_nav`, `nav_order`, `parent_id`, `created_at`, `updated_at`, `created_by`)
VALUES
	(1,'test','Test','Testing','<p>Test content</p>','default','default','standard','grapes','<section class=\"page-hero\">\n    <div class=\"container\">\n        <h1>Test</h1>\n        <p class=\"lead\">Testing</p>\n    </div>\n</section>\n',NULL,NULL,NULL,1,0,0,NULL,'2026-02-08 14:00:56','2026-03-07 16:54:30',1),
	(2,'about','About | Alive Church','Learn about Alive Church Norwich - our mission, vision, values and leadership team.','','default','default','standard','grapes','<section class=\"page-hero\">\n    <div class=\"container\">\n        <h1>About | Alive Church</h1>\n        <p class=\"lead\">Learn about Alive Church Norwich - our mission, vision, values and leadership team.</p>\n    </div>\n</section>\n<section class=\"content-section\" style=\"padding: 60px 20px;\">\n    <div class=\"container\" style=\"max-width: 1200px; margin: 0 auto;\">\n        \n<div class=\"container split\">\n    <div>\n        <h2>Who we are</h2>\n        <p>Alive Church began as a prayer meeting above a shop in Norwich. Today, we gather in our building, homes, and online. Everything we do flows from Jesus\' Great Commission and the Acts 2 church—devoted to teaching, fellowship, generosity, and prayer.</p>\n        <p>We champion unity across generations, creativity that communicates the gospel, and audacious generosity for our cities. We believe in empowering the next generation of leaders through coaching, Alive Leadership College, and hands-on ministry.</p>\n        <img src=\"/assets/imgs/gallery/alive-church-worship-congregation.jpg\" alt=\"Alive Church worship service\" style=\"border-radius: 1rem; margin-top: 1.5rem; box-shadow: 0 20px 40px rgba(75, 38, 121, 0.15); width: 100%;\">\n    </div>\n    <div class=\"card\">\n        <h3>Our values</h3>\n        <ul class=\"info-list\">\n            <li><strong>Presence:</strong> Everything begins with worship.</li>\n            <li><strong>People:</strong> Everyone is seen, known, and needed.</li>\n            <li><strong>Purpose:</strong> We equip everyday saints to influence their world.</li>\n            <li><strong>Play:</strong> Joy is our culture; laughter is welcome.</li>\n        </ul>\n    </div>\n</div>\n    </div>\n</section>\n<section class=\"content-section alt\" style=\"padding: 60px 20px;\">\n    <div class=\"container\" style=\"max-width: 1200px; margin: 0 auto;\">\n        \n<div class=\"container\">\n    <div class=\"section-heading\">\n        <p class=\"eyebrow\">Leadership</p>\n        <h2>Meet some of the vision team.</h2>\n    </div>\n    <div class=\"card-grid profile-grid\">\n        <article class=\"profile-card\">\n            <img src=\"/assets/imgs/gallery/alive-church-congregation-hands-raised.jpg\" alt=\"Pastor speaking at Alive Church\" style=\"border-radius: 0.75rem; margin-bottom: 1rem; width: 100%; height: 200px; object-fit: cover;\">\n            <h3>Pastors Phil & Jo Thorne</h3>\n            <p>Senior Pastors</p>\n            <p>Phil started Alive Church over 40 years ago with a vision for community transformation in Norwich. Phil pastors the church with Jo, his wife. They have both shaped the church we see today.</p>\n        </article>\n        <article class=\"profile-card\">\n            <img src=\"/assets/imgs/gallery/alive-church-worship-leaders-performance.jpg\" alt=\"Worship leaders at Alive Church\" style=\"border-radius: 0.75rem; margin-bottom: 1rem; width: 100%; height: 200px; object-fit: cover;\">\n            <h3>Pastor Jono Thorne</h3>\n            <p>Worship & Creative Pastor</p>\n            <p>Jono oversees many aspects of church life. He is always doing something new and is responsible for Worship, Creative, Youth, Facilities management and Operations in the church.</p>\n        </article>\n        <article class=\"profile-card\">\n            <img src=\"/assets/imgs/gallery/alive-church-live-worship-band-lincolnshire.jpg\" alt=\"Youth worship at Alive Church\" style=\"border-radius: 0.75rem; margin-bottom: 1rem; width: 100%; height: 200px; object-fit: cover;\">\n            <h3>Pastors Jon and Sara Plastow</h3>\n            <p>Pastoral, Children & Compliance</p>\n            <p>Sara grew up in the church, and with her husband Jon, lead many aspects of church life. Sara can often be found preaching, whilst Jon plays drums. Together they lead Kids Church and Jon is trustee of Alive UK.</p>\n        </article>\n        <article class=\"profile-card\">\n            <img src=\"/assets/imgs/gallery/alive-church-live-worship-band-lincolnshire.jpg\" alt=\"Youth worship at Alive Church\" style=\"border-radius: 0.75rem; margin-bottom: 1rem; width: 100%; height: 200px; object-fit: cover;\">\n            <h3>Pastors Abiodun & Ruth</h3>\n            <p>Pastoral Team</p>\n            <p>Abiodun and Ruth are passionate about pastoral care and community outreach. They lead various initiatives to help people connect and grow in their faith journey.</p>\n        </article>\n    </div>\n</div>\n    </div>\n</section>\n','',NULL,NULL,1,0,0,NULL,'2026-02-08 15:33:51','2026-02-14 13:10:37',1),
	(3,'visit','Plan a Visit | Alive Church','Plan your first visit to Alive Church Norwich. Service times, directions, what to expect, and FAQs.','<h2>We Can\'t Waits to Meet You!</h2>\r\n<p>Whether you\'re new to faith, exploring Christianity, or looking for a church home, you are welcome here. Here\'s everything you need to know for your first visit.</p>\r\n<h3>Service Times</h3>\r\n<p><strong>Sunday Gatherings:</strong></p>\r\n<ul>\r\n<li>9:30 AM - Morning Service</li>\r\n<li>11:30 AM - Late Morning Service</li>\r\n</ul>\r\n<p>Both services feature the same worship, message, and experience. Choose the time that works best for you!</p>\r\n<h3>Location &amp; Directions</h3>\r\n<p><strong>Alive Church Norwich</strong><br>123 Faith Street<br>Norwich, Norfolk NR1 1AA</p>\r\n<p><a class=\"btn btn-primary\" href=\"https://maps.google.com/?q=Alive+Church+Norwich\" target=\"_blank\" rel=\"noopener\">Get Directions &rarr;</a></p>\r\n<h3>What to Expect</h3>\r\n<p><strong>Parking:</strong> Free parking is available on-site and on nearby streets. Arrive 10-15 minutes early for the best spots.</p>\r\n<p><strong>Arrival:</strong> Our welcome team will greet you at the entrance and help you find your way. Feel free to grab a coffee in the lobby!</p>\r\n<p><strong>Kids:</strong> We have excellent programs for children from birth through Year 6. Check-in opens 15 minutes before each service.</p>\r\n<p><strong>The Service:</strong> Our services last about 75 minutes and include contemporary worship, Bible teaching, prayer, and communion (first Sunday of each month).</p>\r\n<p><strong>Dress Code:</strong> Come as you are! You\'ll see everything from jeans to suits. We care more about your heart than your wardrobe.</p>\r\n<h3>Frequently Asked Questions</h3>\r\n<p><strong>Will I have to stand out?</strong><br>Not at all! We won\'t single you out or put you on the spot. You\'re welcome to participate as much or as little as you\'re comfortable.</p>\r\n<p><strong>Do I need to bring anything?</strong><br>Just yourself! We provide Bibles, and you can follow along with the message on the screens.</p>\r\n<p><strong>What about my kids?</strong><br>We have age-appropriate programs for all children. Our kids\' ministry teams are background-checked and trained to provide a safe, fun environment.</p>\r\n<p><strong>Is there an offering?</strong><br>We do take an offering during the service, but giving is entirely voluntary. As a guest, you are not expected to contribute.</p>\r\n<p><strong>How can I connect further?</strong><br>After the service, visit our Connect Desk in the lobby. We\'d love to answer questions and help you find ways to get involved.</p>\r\n<h3>Questions?</h3>\r\n<p>If you have any other questions about visiting, feel free to <a href=\"../prayer\">contact us</a>. We\'re here to help!</p>','default','default','standard','grapes','<section class=\"page-hero\">\n    <div class=\"container\">\n        <h1>Plan a Visit | Alive Church</h1>\n        <p class=\"lead\">Plan your first visit to Alive Church Norwich. Service times, directions, what to expect, and FAQs.</p>\n    </div>\n</section>\n',NULL,NULL,NULL,1,0,0,NULL,'2026-02-08 15:33:51','2026-03-05 21:54:23',1),
	(4,'prayer','Prayer Request | Alive Church','Submit a prayer request to Alive Church Norwich. Our prayer team prays daily.','\n<h2>How Can We Pray for You?</h2>\n<p>We believe in the power of prayer and would be honored to pray for you. Whether you\'re facing a challenge, celebrating a victory, or simply need encouragement, our prayer team is here for you.</p>\n\n<h3>Submit a Prayer Request</h3>\n<p>Fill out the form below and our prayer team will lift your request before God. All requests are kept confidential.</p>\n\n<p><em>Prayer request form will appear here when integrated with the existing contact form system.</em></p>\n\n<h3>Get in Touch</h3>\n<p>Have a question or want to connect with our team? We\'d love to hear from you!</p>\n\n<p><strong>Office Hours:</strong><br>\nMonday - Friday: 9:00 AM - 4:00 PM</p>\n\n<p><strong>Phone:</strong> 01603 123456<br>\n<strong>Email:</strong> hello@alivechurch.org.uk</p>\n\n<p><strong>Address:</strong><br>\nAlive Church<br>\n123 Faith Street<br>\nNorwich, Norfolk NR1 1AA</p>\n\n<h3>Emergency Pastoral Care</h3>\n<p>If you have an urgent pastoral need outside of office hours, please call our pastoral emergency line: 07700 900000</p>\n\n<h3>Connect With Us</h3>\n<p>Follow us on social media to stay updated on events, messages, and church news:</p>\n<ul>\n    <li>Facebook: @AliveChurchNorwich</li>\n    <li>Instagram: @alivechurchnorwich</li>\n    <li>YouTube: Alive Church Norwich</li>\n</ul>\n','default','default','standard','grapes','<section class=\"page-hero\">\n    <div class=\"container\">\n        <h1>Prayer Request | Alive Church</h1>\n        <p class=\"lead\">Submit a prayer request to Alive Church Norwich. Our prayer team prays daily.</p>\n    </div>\n</section>\n',NULL,NULL,NULL,1,0,0,NULL,'2026-02-08 15:33:51','2026-02-16 12:04:49',1),
	(5,'echo','ECHO','',NULL,'full-width','default','standard','grapes',NULL,NULL,NULL,NULL,1,0,0,NULL,'2026-03-05 20:56:29','2026-03-05 20:58:47',1),
