	(1,'Guest Experience Team','Be the first smile people see when they walk in. Help with parking, hosting, coffee, and connections.','Once a month','[\"Parking\", \"Hosting\", \"Coffee Bar\", \"Connection Points\"]','/assets/imgs/gallery/alive-church-christmas-service-celebration.jpg',0,1,'2026-02-07 16:23:50','2026-02-07 16:23:50'),
	(2,'Kids Ministry','Help kids discover Jesus through games, teaching, and fun. Make Sunday the best day of their week!','Twice a month','[\"Nursery\", \"Preschool\", \"Elementary\", \"Check-In\"]','/assets/imgs/gallery/alive-church-family-worship-lincolnshire.jpg',1,1,'2026-02-07 16:23:50','2026-02-07 16:23:50'),
	(3,'Worship Team','Use your musical gifts to lead people into God\'s presence through passionate worship.','Once a month','[\"Vocals\", \"Band\", \"Tech/Sound\", \"Media\"]','/assets/imgs/gallery/alive-church-worship-team-stage.jpg',2,1,'2026-02-07 16:23:50','2026-02-07 16:23:50'),
	(4,'Prayer Team','Intercede for our church, city, and world. Serve on Sundays or join the prayer room team.','Flexible','[\"Sunday Prayer\", \"Prayer Room\", \"Email Prayer\"]','/assets/imgs/gallery/alive-church-acoustic-worship-prayer.jpg',3,1,'2026-02-07 16:23:50','2026-02-07 16:23:50');
