INSERT INTO `user_highlights` (`id`, `user_id`, `study_id`, `highlighted_text`, `start_offset`, `end_offset`, `color`, `note`, `created_at`, `updated_at`)
VALUES
	(8,1,4,'Romans 8 is the mountaintop of Paul\'s letter to the Romans. After explaining humanity\'s sin problem (chapters 1-3), God\'s solution through faith (chapters 4-5), and our struggle with sin (chapters 6-7), Paul now declares the glorious freedom we have in Christ. This chapter moves from \"no condemnation\" to \"no separation\"—and everything in between is pure gold.',0,361,'yellow',NULL,'2026-03-06 13:59:36','2026-03-06 13:59:36'),
	(23,1,21,'enesis 15:6), yet humans struggle to wait on His timing, leading to disastrous attempts to force promises. These chapters highlight God\'s patience, the necessity of trust, and His care for the outcast (Hagar).\r\n\r\nGod\'s Promise to Abram',0,233,'yellow',NULL,'2026-03-06 18:50:18','2026-03-06 18:50:18'),
	(24,1,18,'ave their comfort zones and trust in God\'s promises despite uncertain circumstances. It highlights God\'s covenant initiative to bless humanity through Abraham, providi',0,167,'pink',NULL,'2026-03-06 19:19:13','2026-03-06 19:19:13'),
	(26,1,18,'is homeland (Ur and later Haran) to separate him from idolatrous influences, initiate a new nation, and fulfil a promise to make him a blessing to all families of the earth.',0,173,'blue',NULL,'2026-03-06 19:19:19','2026-03-06 19:19:19'),
	(27,1,18,'and his fat',0,11,'orange',NULL,'2026-03-06 19:19:24','2026-03-06 19:19:24'),
	(30,1,23,'er will you be called Abram; your name will be Abraham, for I have made you a father of many nations.\"\r\nSarai to Sarah: [15] \"As for Sarai your wife,',0,148,'yellow',NULL,'2026-03-06 19:22:24','2026-03-06 19:22:24'),
	(32,1,18,'The Abrahamic Covenant',0,22,'yellow',NULL,'2026-03-06 19:25:31','2026-03-06 19:25:31'),
	(34,1,18,'is homeland was not conducive to his calling.\r\nThe Abrahamic Covenant\r\n\r\n[2-3] God\'s promises to Abram form the foundation of the Abrahamic Covenant:\r\n\r\nKey Commandments',0,164,'pink',NULL,'2026-03-06 19:25:41','2026-03-06 19:25:41'),
	(35,1,18,'homeland',0,8,'green',NULL,'2026-03-06 19:25:46','2026-03-06 19:25:46'),
	(36,1,18,'Spiritual Growth: The environment in his homeland was not conducive to his calling.',0,83,'green',NULL,'2026-03-06 19:25:50','2026-03-06 19:25:50'),
	(39,1,18,'will curse.\"\r\nUniversal Blessing: [3] \"All peoples on earth will be blessed through you.\"\r\nAbram\'s Obedience\r\n\r\n[4-9] Abram demonstrates faith by obeying God\'s call:',0,161,'green',NULL,'2026-03-06 19:33:19','2026-03-06 19:33:19'),
	(40,1,18,'Descendants: [2] To make him a \"great nation.\"\r\nLand: To give his descendants the land of Canaan.\r\nBlessing: [2] To bless him and make his name great.\r\nProtection: [3] \"I will bless those who bless you, and whoever curses you I will curse.\"\r\nUniversal Blessing: [3] \"All peoples on earth will be blessed through you.\"\r\nAbram\'s Obedience\r\n\r\n[4-9] Abram demonstrates faith by obeying God\'s call:\r\n\r\n[4] Abram went, as the LORD had told him, takin',0,435,'orange',NULL,'2026-03-06 19:33:45','2026-03-06 19:33:45'),
	(42,1,18,'[8] He moved on to the hills east of Bethel and built another altar, calling on the name of the LORD.\r\nAbram\'s Failure in Egypt\r\n\r\n[10-20] Even in a moment of fear during the famine in Egypt, Abram lies about Sarai being his sister:\r\n\r\n[10-13] A famine drove A',0,255,'green',NULL,'2026-03-06 19:37:07','2026-03-06 19:37:07'),
	(44,1,31,'Genesis 24 is one of the most beautiful stories of divine providence in Scripture. Abraham\'s servant finds Rebekah for Isaac through specific prayer',0,148,'blue',NULL,'2026-03-06 19:54:09','2026-03-06 19:54:09'),
	(45,1,31,'unmistakable signs, demonstrating how God guides those who seek Him in the details of life.',0,91,'pink',NULL,'2026-03-06 19:54:12','2026-03-06 19:54:12'),
	(46,1,31,'Abraham\'s Commission\r\n[1-9] Abraham sends his servant on an important mission:',0,77,'orange',NULL,'2026-03-06 19:54:18','2026-03-06 19:54:18'),
	(47,6,34,'Jacob stopped for the night and used a stone for a pillow. He dreamed of a stairway resting on the earth with its top reaching to heaven, and the angels of God ascending and descending on it.',0,191,'yellow',NULL,'2026-03-06 21:13:13','2026-03-06 21:13:13'),
	(48,6,20,'Genesis 14 records the first war in the Bible and Abram\'s courageous rescue of his nephew Lot. It introduces the mysterious figure of Melchizedek and demonstrates Abram\'s integrity in refusing to take spoils from the wicked king of Sodom.',0,238,'blue',NULL,'2026-03-06 21:13:27','2026-03-06 21:13:27'),
	(49,6,20,'Selfless Action and Loyalty: Despite Lot choosing the better land and separating from him, Abram did not hesitate to risk his life to save his nephew.',0,150,'orange',NULL,'2026-03-06 21:13:35','2026-03-06 21:13:35'),
	(50,1,31,'made his servant swear not to get a wife for Isaac from the Canaanites, but to go',0,81,'blue',NULL,'2026-03-06 22:06:40','2026-03-06 22:06:40'),
	(51,1,31,'out an instance from your own past in which you can see the hand of God at wor',0,78,'pink',NULL,'2026-03-06 22:09:22','2026-03-06 22:09:22'),
	(52,1,2,'John\'s opening echoes Genesis 1:1, immediately establishing that Jesus—the Word (Greek: Logos)—existed before all creation.',0,123,'yellow',NULL,'2026-03-07 10:43:05','2026-03-07 10:43:05'),
	(53,1,32,'the',0,3,'blue',NULL,'2026-03-07 11:57:15','2026-03-07 11:57:15'),
	(54,1,7,'God\'s image to reflect His character and steward the earth.\r\n\r\nWhat Can We Learn from God\'s Creation Process?\r\n\r\n[1-2] God\'s creation process reveals Him a',0,151,'pink',NULL,'2026-03-07 12:25:24','2026-03-07 12:25:24'),
	(55,1,7,'and purpos',0,10,'yellow',NULL,'2026-03-07 12:25:33','2026-03-07 12:25:33'),
	(58,6,5,'ollowed the ways of this world and of the ruler of the kingdom of the air, the spirit who is now at work in those who are disobedient. All of us also lived among them at one time, gra',0,183,'blue',NULL,'2026-03-08 10:14:53','2026-03-08 10:14:53'),
	(59,6,5,'our condition apart from Christ. We weren\'t merely sick or struggling—we were dead. Spiritually lifeless. Following the world, the flesh, and the devil. This is why self-improvement',0,181,'pink',NULL,'2026-03-08 10:14:56','2026-03-08 10:14:56'),
	(60,6,7,'ntionally brought the universe into existence, transforming chaos into an ordered, good, and purposeful world. It reveals humanity as the pinnacle of creation, made in God\'s image to reflect His character an',0,207,'blue',NULL,'2026-03-08 14:45:01','2026-03-08 14:45:01'),
	(61,6,7,'earn from God\'s Creati',0,22,'orange',NULL,'2026-03-08 14:45:03','2026-03-08 14:45:03'),
	(62,6,7,'t of chaos. It highlight',0,24,'yellow',NULL,'2026-03-08 14:45:05','2026-03-08 14:45:05'),
	(63,6,7,'Order and Purpose: God did not create randomly; the process was deliberate (forming and filling).',0,97,'green',NULL,'2026-03-10 20:17:13','2026-03-10 20:17:13');
