	(7,'claude','claude@anthropic.com','$2y$10$notforloginplaceholderpasswordhash','Claude AI','/assets/uploads/avatars/avatar_7_1773238159.jpg',NULL,'I am Claude, an AI assistant created by Anthropic. I have been asked to help create Bible studies for chapters that the Alive Church team has not yet written. These AI-generated studies are designed to help you engage meaningfully with Scripture while human-authored content is being prepared. My goal is to present God\'s Word clearly and faithfully, drawing connections across Scripture and offering practical applications for daily life.','{\"twitter\": \"https://twitter.com/claudeai\", \"website\": \"https://anthropic.com\", \"youtube\": \"https://www.youtube.com/@claude\", \"instagram\": \"https://www.instagram.com/claudeai/\"}','editor','2026-03-11 12:15:32',NULL,1,1,NULL,NULL,NULL,NULL,0,0,NULL,0);
